const items = $json.data || [];
const total = items.reduce((s, i) => s + parseFloat(i.amount || 0), 0);
const lines = items.map(i => `• ${i.vendor} — ${i.currency||'GBP'} ${i.amount} (due ${i.due_date})`);
const emailRows = items.map(i => `<tr><td>${i.vendor}</td><td>${i.currency||'GBP'} ${i.amount}</td><td>${i.date}</td><td style='color:red'>${i.due_date}</td><td>${i.source_channel}</td></tr>`).join('');
return [{ json: { count: items.length, total: total.toFixed(2), lines: lines.join('\n'), emailRows, items } }];

