const resp=$input.first().json.response||'{}';
const orig=$input.first().json;
let parsed;
try {
  const match=resp.match(/\{[\s\S]*\}/);
  parsed=JSON.parse(match?match[0]:resp);
} catch(e) {
  parsed={
    category:'Uncategorized',vendor:orig.vendor||'Unknown',amount:orig.amount||0,
    doc_type:orig.doc_type||'invoice',anomaly_flag:true,anomaly_severity:'high',
    anomaly_reason:'AI parse failure Ã¢â‚¬â€ manual review required',
    anomaly_recommendations:['Manual review required'],confidence_score:0,
    priority:'high',action_required:'Manual review needed'
  };
}
const recs=Array.isArray(parsed.anomaly_recommendations)?parsed.anomaly_recommendations.join('; '):(parsed.anomaly_recommendations||'');
return [{json:{
  ...orig,...parsed,
  category:parsed.category||orig.category||'Uncategorized',
  vendor:parsed.vendor||orig.vendor||'Unknown',
  amount:parseFloat(parsed.amount||orig.amount||0),
  currency:parsed.currency||orig.currency||'GBP',
  date:parsed.date||orig.date||new Date().toISOString().split('T')[0],
  due_date:parsed.due_date||orig.due_date||null,
  doc_type:parsed.doc_type||orig.doc_type||'invoice',
  vat_amount:parseFloat(parsed.vat_amount||0)||null,
  vat_reclaimable:parsed.vat_reclaimable||false,
  is_recurring:parsed.is_recurring||false,
  source_channel:orig.source_channel||'unknown',
  sender_id:orig.sender_id||'unknown',
  anomaly_recommendations:recs,
  processed_date:new Date().toISOString()
}}];

const body=$input.first().json.body||$input.first().json;
const type=(body.type||'weekly').toLowerCase();
const channel=(body.channel||'all').toLowerCase();
const now=new Date();
let dateFrom;
if(type==='daily'){dateFrom=new Date(now-86400000).toISOString();}
else if(type==='weekly'){dateFrom=new Date(now-7*86400000).toISOString();}
else if(type==='monthly'){const d=new Date(now);d.setMonth(d.getMonth()-1);dateFrom=d.toISOString();}
else if(type==='custom'&&body.from_date){dateFrom=new Date(body.from_date).toISOString();}
else{dateFrom=new Date(now-7*86400000).toISOString();}
const dateTo=body.to_date?new Date(body.to_date).toISOString():now.toISOString();
return[{json:{
  report_type:type,channel,date_from:dateFrom,date_to:dateTo,
  recipient_email:body.recipient_email||null,
  recipient_phone:body.recipient_phone||null,
  requested_at:now.toISOString()
}}];

const r=$input.first().json.response||'';
const orig=$input.first().json;
const em=r.match(/\[EMAIL\]([\s\S]*?)\[\/EMAIL\]/);
const mm=r.match(/\[MSG\]([\s\S]*?)\[\/MSG\]/);
const ec=em?em[1].trim():r;
const mc=mm?mm[1].trim():r.substring(0,800);
const sid=process.env.FINANCE_SPREADSHEET_ID||'1BxiMVs0XRA5nFMdKvBdBZjgmUUqptlbs74OgVE2upms';
const sheetsUrl='https://docs.google.com/spreadsheets/d/'+sid+'/edit#gid=0';
return[{json:{...orig,email_content:ec,msg_content:mc,sheets_url:sheetsUrl,channel:orig.channel||'all'}}];

const items=$input.all();
if(!items||!items.length)return[];
const invList=items.map(i=>i.json);
const lines=invList.map(inv=>{
  const due=inv.due_date?new Date(inv.due_date).toLocaleDateString('en-GB'):'N/A';
  const amt=inv.amount?'GBP'+parseFloat(inv.amount).toFixed(2):'unknown';
  return '- '+(inv.vendor||'Unknown')+' | '+amt+' | Due: '+due+' | Ref: '+(inv.reference_number||'-');
});
const emailHtml='<h2>Payment Due in 3 Days</h2><p>'+invList.length+' invoice(s) require attention:</p><ul>'+
  invList.map(inv=>{
    const due=inv.due_date?new Date(inv.due_date).toLocaleDateString('en-GB'):'N/A';
    const amt=inv.amount?'GBP'+parseFloat(inv.amount).toFixed(2):'?';
    return '<li><b>'+(inv.vendor||'?')+'</b> - '+amt+' due '+due+'</li>';
  }).join('')+'</ul><p>Please process payment promptly to avoid late fees.</p>';
const msg='Payment Due Alert\n\n'+lines.join('\n')+'\n\nPlease process payments now.';
return[{json:{email_html:emailHtml,telegram_msg:msg,wa_msg:msg,invoice_count:invList.length}}];
